import{_ as e,o as n,c as a,a2 as t}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員 (finance-investment-researcher) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F16_大股東成本與籌碼結構審計_投資研究員_審計報告.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F16_大股東成本與籌碼結構審計_投資研究員_審計報告.md"}'),o={name:"審計報告庫/財務審計/3189_景碩/20260423/F16_大股東成本與籌碼結構審計_投資研究員_審計報告.md"};function i(s,r,l,_,d,c){return n(),a("div",null,[...r[0]||(r[0]=[t('<h1 id="f16-大股東成本與籌碼結構審計-投資研究員-finance-investment-researcher-審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員 (finance-investment-researcher) 審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員-finance-investment-researcher-審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員 (finance-investment-researcher) 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p><strong>評級：A (良)</strong>。根據截至 2026 年 3 月最新公開數據，景碩董監事合計持股 28.46%，屬利益深度綑綁型態。董監質押率僅 0.25%，幾無斷頭風險。大股東華瑋/華毓/華旭等關係企業合計持股 42.44%，展現極強的控制力與長期持有意願。2026 年 3 月現增 145 元定價已確認大股東的實際增資成本。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>董監持股比例</strong>：2026 年 3 月董監事合計持股 130,033 張，佔發行股數 (526,925 張) 的 28.46%。較 2025 年底的 25.25% 上升，主因為 2026 年 3 月完成 70,000 張現金增資，大股東積極認購。</li><li><strong>質押水位</strong>：董監事質押總張數僅 330 張 (董事陳河旭個人質押)，佔董監持股的 0.25%。極低質押率顯示大股東無迫切的個人財務槓桿壓力。</li><li><strong>大股東集團</strong>：華瑋投資 67,037 張 (14.67%) + 華毓投資 61,940 張 (13.56%) + 華旭投資 64,924 張 (14.21%) = 193,901 張 (42.44%)，三者均為和碩集團關聯企業，顯示童子賢/華碩體系對景碩的戰略控制力。</li><li><strong>內部人成本錨定</strong>：2026 年現增認購價 145 元為大股東明確的成本錨點；歷史增持點位約在 100-180 元區間，大股東平均成本約 120-150 元，較市價 (479 元) 浮盈約 220-300%。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>近期持股變動分析</strong>： 2025 年底至 2026 年 3 月，董監持股比率自 25.25% 上升至 28.47%，主因有二： (1) 2026-01-27 至 2026-02-25 間完成私募/庫藏股轉讓，大股東華瑋/華毓/華旭透過參與現增積極墊高持股； (2) 2026-03-17 現金增資 70,000 張後，大股東繳款參與率極高，未見放棄認購的減持行為。</p><p>從股權分散表 (backer_holding) 追溯：2026-03-17 增資基準日前，千張以上大戶 (51 人) 持股 333,956 張 (63.37%)；增資後 2026-04-17 千張大戶 (50 人) 持股 327,745 張 (62.19%)，比例微降 1.18 百分點，主要是分母擴大效應，絕對張數仍維持穩定。</p><p><strong>質押爆雷情景模擬</strong>： 質押率僅 0.25%，陳河旭個人質押 330 張。假設設質押成數 60%、維持率 130%：以 2026-04-23 收盤價 479 元計，維持股價下限為 479 × 60% × 130% = 373 元。距當前仍有 22% 安全空間。且因質押規模極小，即便斷頭對市場衝擊也微乎其微。</p><p><strong>利益綑綁度評估</strong>： 關鍵董事長廖賜政 (持股 648 張)、副董事長童子賢 (806 張) 均持有少量個人股，無近期減持紀錄。總經理陳河旭雖有 330 張質押，但同時也是公司經營層，29.08% 的個人質押率尚在合理範圍，不宜過度解讀為撤退信號。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>華爾街空頭視角</strong>：</p><ol><li><strong>關係人集中度風險</strong>：和碩集團合計控制約 42% 股權，雖然展現長期承諾，但也意味著公司治理獨立性不足。外部小股東在重大投票中缺乏制衡力。</li><li><strong>現增定價偏低爭議</strong>：2026 年 3 月現增訂價 145 元，當時市價已在 300-400 元區間。大股東以折價約 50-60% 取得新股，對參與現增的特定人而言利益豐厚，但對未參與增資的小股東構成稀釋。</li><li><strong>歷史減持風險</strong>：應監控 2025 年以來董監事與內部人是否出現「股價暴漲後減持」的模式。目前未見異常，但若股價突破 600 元，須密切關注集保異動公告。</li><li><strong>控制權穩定性</strong>：華瑋+華毓+華旭集團結構穩定，未來 3-5 年內控制權移轉風險極低。這對中長期投資者是正面信號。</li></ol><p><strong>結論</strong>：籌碼結構極具防禦性，大股東集團持股高度集中且無質押壓力，核心經營層利益與公司深度綑綁。惟需注意集團控制權集中帶來的治理透明度風險。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>FinMind 董監持股查詢</strong>: <code>holding 3189 2023-01-01 2026-04-23 --df</code> (科目：外資持股張數、大股東持股張數、持股百分比)</li><li><strong>FinMind 股權分散表查詢</strong>: <code>backer_holding 3189 2023-01-01 2026-04-23 --df</code> (科目：分級持股張數、佔比、戶數)</li><li><strong>富聯網董監持股概況</strong>: moneylink.com.tw (資料日期 2026/03，檢索董監質押明細)</li><li><strong>財報狗</strong>: statementdog.com/analysis/3189/board-members-and-supervisors-shares (董監持股比例 28.47% 確認)</li><li><strong>FinMind 股利政策查詢</strong>: <code>dividend 3189 2020-01-01 2026-04-23 --df</code> (現增 70,000 張，認購價 145 元)</li><li><strong>數據更新日期</strong>: 2026 年 3 月董監持股月報 (2026-03-31)</li></ul>',18)])])}const p=e(o,[["render",i]]);export{g as __pageData,p as default};
